const W=Math.min(innerWidth,480),H=innerHeight;class S extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x0f172a);this.cells=[];for(let i=0;i<24;i++){const x=50+(i%6)*70,y=90+((i/6)|0)*80;const c=this.add.circle(x,y,24,0x334155).setInteractive();c.owner=0;c.on('pointerdown',()=>this.take(c));this.cells.push(c);}this.turn=1;this.ui=this.add.text(10,10,'P1:0 P2:0');this.r=this.input.keyboard.addKey('R');}take(c){if(this.over||c.owner===this.turn)return;c.owner=this.turn;c.setFillStyle(this.turn===1?0x60a5fa:0xf472b6);this.turn=this.turn===1?2:1;const p1=this.cells.filter(v=>v.owner===1).length,p2=this.cells.filter(v=>v.owner===2).length;this.ui.setText(`P1:${p1} P2:${p2}`);if(p1+p2===24){this.over=true;this.add.text(W/2,H-40,p1===p2?'DRAW R':(p1>p2?'P1 WIN R':'P2 WIN R')).setOrigin(.5);}}update(){if(this.r.isDown)this.scene.restart();}}
new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,scene:[S]});
